-- Tabla institucional EID adaptada desde el respaldo MariaDB para uso en Supabase/PostgreSQL.
-- Base de origen: supabase/EID.sql

create table if not exists public.eid (
  id bigint generated by default as identity primary key,
  dimension varchar(150) not null,
  sub_dimension varchar(255) not null,
  numero_estandar varchar(20) not null,
  descripcion_estandar text not null
);

create unique index if not exists eid_numero_estandar_key on public.eid (numero_estandar);
create index if not exists eid_dimension_idx on public.eid (dimension);
create index if not exists eid_sub_dimension_idx on public.eid (sub_dimension);

on conflict (id) do update
set
  dimension = excluded.dimension,
  sub_dimension = excluded.sub_dimension,
  numero_estandar = excluded.numero_estandar,
  descripcion_estandar = excluded.descripcion_estandar;

select setval(
  pg_get_serial_sequence('public.eid', 'id'),
  coalesce((select max(id) from public.eid), 1),
  true
);